ATOM = 1e-12


def close_enough(a: float, b: float, tol: float = 1e-12) -> bool:
    return abs(a - b) < tol


@dataclass
class Point:
    """数值点表示"""

    x: float
    y: float
    name: str = ""

    def __lt__(self, other: "Point") -> bool:
        return (self.x, self.y) < (other.x, other.y)

    def __gt__(self, other: "Point") -> bool:
        return (self.x, self.y) > (other.x, other.y)

    def __add__(self, p: "Point") -> "Point":
        return Point(self.x + p.x, self.y + p.y)

    def __sub__(self, p: "Point") -> "Point":
        return Point(self.x - p.x, self.y - p.y)

    def __mul__(self, f: float) -> "Point":
        return Point(self.x * f, self.y * f)

    def __rmul__(self, f: float) -> "Point":
        return self * f

    def __truediv__(self, f: float) -> "Point":
        return Point(self.x / f, self.y / f)

    def __str__(self) -> str:
        return f"P({self.x},{self.y})"

    def __hash__(self) -> int:
        return hash((round(self.x, 10), round(self.y, 10), self.name))

    def __eq__(self, other: object) -> bool:
        if not isinstance(other, Point):
            return False
        return close_enough(self.x, other.x) and close_enough(self.y, other.y)

    def close(self, point: "Point", tol: float = 1e-12) -> bool:
        return abs(self.x - point.x) < tol and abs(self.y - point.y) < tol

    def distance(self, p: "Point") -> float:
        dx = self.x - p.x
        dy = self.y - p.y
        return math.sqrt(dx * dx + dy * dy)

    def distance2(self, p: "Point") -> float:
        dx = self.x - p.x
        dy = self.y - p.y
        return dx * dx + dy * dy

    def rotate(self, sinb: float, cosb: float) -> "Point":
        x, y = self.x, self.y
        return Point(x * cosb - y * sinb, x * sinb + y * cosb)

    def rotatea(self, ang: float) -> "Point":
        sinb, cosb = math.sin(ang), math.cos(ang)
        return self.rotate(sinb, cosb)

    def norm(self) -> float:
        return math.sqrt(self.x**2 + self.y**2)

    def dot(self, other: "Point") -> float:
        return self.x * other.x + self.y * other.y


class Line:
    """数值线表示"""

    def __init__(
        self,
        p1: Optional["Point"] = None,
        p2: Optional["Point"] = None,
        coefficients: Optional[Tuple[float, float, float]] = None,
    ):
        self.coefficients: Tuple[Optional[float], Optional[float], Optional[float]] = (
            None,
            None,
            None,
        )
        if p1 is None and p2 is None and coefficients is None:
            return

        if coefficients is not None:
            a, b, c = coefficients
        elif p1 is not None and p2 is not None:
            a, b, c = (
                p1.y - p2.y,
                p2.x - p1.x,
                p1.x * p2.y - p2.x * p1.y,
            )
        else:
            self.coefficients = (None, None, None)  #
            return

        if a < 0.0 or a == 0.0 and b > 0.0:
            a, b, c = -a, -b, -c

        self.coefficients = (a, b, c)  #

    def __call__(self, x: float, y: float) -> float:
        a, b, c = self.coefficients
        if a is None or b is None or c is None:
            return 0.0  #
        return x * a + y * b + c  #

    def is_parallel(self, other: "Line") -> bool:
        a, b, _ = self.coefficients
        x, y, _ = other.coefficients
        if a is None or b is None or x is None or y is None:
            return False
        return abs(a * y - b * x) < ATOM

    def is_perp(self, other: "Line") -> bool:
        a, b, _ = self.coefficients
        x, y, _ = other.coefficients
        if a is None or b is None or x is None or y is None:
            return False
        return abs(a * x + b * y) < ATOM

    def distance(self, p: Point) -> float:
        a, b, _ = self.coefficients
        if a is None or b is None:
            return 0.0
        return abs(self(p.x, p.y)) / math.sqrt(a * a + b * b)  #

    def perpendicular_line(self, p: Point) -> "Line":
        a, b, _ = self.coefficients
        if a is None or b is None:
            return Line()
        return Line(p, p + Point(a, b))  #

    def parallel_line(self, p: Point) -> "Line":
        a, b, _ = self.coefficients
        if a is None or b is None:
            return Line()
        return Line(coefficients=(a, b, -a * p.x - b * p.y))  #

    def same(self, other: "Line") -> bool:
        a, b, c = self.coefficients
        x, y, z = other.coefficients
        if a is None or b is None or c is None or x is None or y is None or z is None:
            return False
        return close_enough(a * y, b * x) and close_enough(b * z, c * y)  #


class Circle:
    """数值圆表示"""

    def __init__(
        self,
        center: Optional[Point] = None,
        radius: Optional[float] = None,
        p1: Optional[Point] = None,
        p2: Optional[Point] = None,
        p3: Optional[Point] = None,
    ):
        self.center: Optional[Point] = None
        self.a: float = 0.0
        self.b: float = 0.0
        self.radius: Optional[float] = None
        self.r2: Optional[float] = None

        if not center:
            if not (p1 and p2 and p3):
                return

            l12 = perpendicular_bisector(p1, p2)
            l23 = perpendicular_bisector(p2, p3)
            center = line_line_intersection(l12, l23)

        self.center = center
        if center is not None:
            self.a, self.b = center.x, center.y  #
        else:
            self.a, self.b = 0.0, 0.0

        if not radius:
            p = p1 or p2 or p3
            if p is None:
                return
            self.r2 = (self.a - p.x) ** 2 + (self.b - p.y) ** 2  #
            self.radius = math.sqrt(self.r2)  #
        else:
            self.radius = radius
            self.r2 = radius * radius


def perpendicular_bisector(p1: Point, p2: Point) -> Line:
    midpoint = (p1 + p2) * 0.5
    return Line(midpoint, midpoint + Point(p2.y - p1.y, p1.x - p2.x))


def line_line_intersection(l1: Line, l2: Line) -> Point:
    a1, b1, c1 = l1.coefficients
    a2, b2, c2 = l2.coefficients
    if a1 is None or b1 is None or c1 is None or a2 is None or b2 is None or c2 is None:
        raise ValueError("Line coefficients not defined")
    d = a1 * b2 - a2 * b1
    if d == 0:
        raise ValueError("Lines are parallel")
    return Point((c2 * b1 - c1 * b2) / d, (c1 * a2 - c2 * a1) / d)


def line_circle_intersection(line: Line, circle: Circle) -> Tuple[Point, Point]:
    a, b, c = line.coefficients
    if a is None or b is None or c is None:
        raise ValueError("Line coefficients not defined")
    r = circle.radius
    center = circle.center
    if r is None or center is None:
        raise ValueError("Circle not defined")
    p, q = center.x, center.y

    if b == 0:
        x = -c / a
        x_p = x - p
        x_p2 = x_p * x_p
        disc = r * r - x_p2
        if disc < 0:
            raise ValueError("No intersection")
        y1 = q + math.sqrt(disc)
        y2 = q - math.sqrt(disc)
        return Point(x, y1), Point(x, y2)

    if a == 0:
        y = -c / b
        y_q = y - q
        y_q2 = y_q * y_q
        disc = r * r - y_q2
        if disc < 0:
            raise ValueError("No intersection")
        x1 = p + math.sqrt(disc)
        x2 = p - math.sqrt(disc)
        return Point(x1, y), Point(x2, y)

    c_ap = c + a * p
    a2 = a * a
    qa = a2 + b * b
    qb = 2 * (b * c_ap - a2 * q)
    qc = c_ap * c_ap + a2 * (q * q - r * r)
    disc = qb * qb - 4 * qa * qc
    if disc < 0:
        raise ValueError("No intersection")
    y1 = (-qb + math.sqrt(disc)) / (2 * qa)
    y2 = (-qb - math.sqrt(disc)) / (2 * qa)
    return Point(-(b * y1 + c) / a, y1), Point(-(b * y2 + c) / a, y2)


def circle_circle_intersection(c1: Circle, c2: Circle) -> Tuple[Point, Point]:
    x0, y0, r0 = c1.a, c1.b, c1.radius
    x1, y1, r1 = c2.a, c2.b, c2.radius
    if r0 is None or r1 is None:
        raise ValueError("Circle radius not defined")

    d = math.sqrt((x1 - x0) ** 2 + (y1 - y0) ** 2)
    if d == 0:
        raise ValueError("Circles are concentric")

    a = (r0**2 - r1**2 + d**2) / (2 * d)
    h = r0**2 - a**2
    if h < 0:
        raise ValueError("No intersection")
    h = math.sqrt(h)
    x2 = x0 + a * (x1 - x0) / d
    y2 = y0 + a * (y1 - y0) / d
    x3 = x2 + h * (y1 - y0) / d
    y3 = y2 - h * (x1 - x0) / d
    x4 = x2 - h * (y1 - y0) / d
    y4 = y2 + h * (x1 - x0) / d

    return Point(x3, y3), Point(x4, y4)


class GeomNode:
    """几何图节点基类"""

    def __init__(self, name: str = "", graph: Any = None):
        self.name = name or str(self)
        self.graph = graph
        self.edge_graph: Dict["GeomNode", Dict["GeomNode", Any]] = {}
        self.merge_graph: Dict["GeomNode", Any] = {}
        self.rep_by: Optional["GeomNode"] = None
        self.members: Set["GeomNode"] = {self}
        self._val: Optional["GeomNode"] = None
        self._obj: Optional["GeomNode"] = None
        self.deps: List[Any] = []
        self.num: Any = None
        self.points: Tuple["GeomNode", ...] = ()
        self._lengths: Tuple[Optional["GeomLength"], Optional["GeomLength"]] = (
            None,
            None,
        )
        self._directions: Tuple[
            Optional["GeomDirection"], Optional["GeomDirection"]
        ] = (None, None)

    def merge(self, nodes: List["GeomNode"], deps: Any) -> None:
        for node in nodes:
            self.merge_one(node, deps)

    def why_equal(
        self, nodes: List["GeomNode"], level: Union[int, float]
    ) -> Optional[Any]:
        # Simple implementation or stub
        if self in nodes:
            return []  # Found equality
        return None

    def rep(self) -> "GeomNode":
        x = self
        while x.rep_by:
            x = x.rep_by
        return x

    def neighbors(
        self,
        oftype: Optional[type] = None,
        return_set: bool = False,
        do_rep: bool = True,
    ) -> Union[List["GeomNode"], Set["GeomNode"]]:
        if do_rep:
            rep = self.rep()
        else:
            rep = self
        result: Set["GeomNode"] = set()

        for n in rep.edge_graph:
            if oftype is None or oftype and isinstance(n, oftype):
                if do_rep:
                    result.add(n.rep())
                else:
                    result.add(n)

        if return_set:
            return result
        return list(result)

    def connect_to(self, node: "GeomNode", deps: Any = None) -> None:
        rep = self.rep()

        if node in rep.edge_graph:
            rep.edge_graph[node].update({self: deps})
        else:
            rep.edge_graph[node] = {self: deps}

    def merge_one(self, node: "GeomNode", deps: Any) -> None:
        node.rep().set_rep(self.rep())

        if node in self.merge_graph:
            return

        self.merge_graph[node] = deps
        node.merge_graph[self] = deps

    def set_rep(self, node: "GeomNode") -> None:
        if node == self:
            return
        self.rep_by = node
        node.merge_edge_graph(self.edge_graph)
        node.members.update(self.members)

    def merge_edge_graph(
        self, new_edge_graph: Dict["GeomNode", Dict["GeomNode", Any]]
    ) -> None:
        for x, xdict in new_edge_graph.items():
            if x in self.edge_graph:
                self.edge_graph[x].update(dict(xdict))
            else:
                self.edge_graph[x] = dict(xdict)


