class Dependency:
    """依赖关系"""

    def __init__(
        self,
        name: str,
        args: List[Any],
        rule_name: str = "",
        level: Optional[int] = None,
    ):
        self.name = name
        self.args = args
        self.rule_name = rule_name
        self.level = level
        self.why: List["Dependency"] = []
        self.algebra: Any = None

    def hashed(self) -> Tuple[str, ...]:
        args = [p.name if hasattr(p, "name") else str(p) for p in self.args]
        return hashed(self.name, args)


def hashed(name: str, args: List[str]) -> Tuple[str, ...]:
    if name in ["npara", "nperp", "para", "cong", "perp", "collx"]:
        a, b, c, d = args
        a, b = sorted([a, b])
        c, d = sorted([c, d])
        (a, b), (c, d) = sorted([(a, b), (c, d)])
        return (name, a, b, c, d)

    if name in ["midp", "midpoint"]:
        a, b, c = args
        b, c = sorted([b, c])
        return (name, a, b, c)

    if name in ["coll", "cyclic", "ncoll", "diff", "triangle"]:
        return (name,) + tuple(sorted(list(set(args))))

    if name == "circle":
        x, a, b, c = args
        return (name, x) + tuple(sorted([a, b, c]))

    if name in ["eqangle", "eqratio", "eqangle6", "eqratio6"]:
        a, b, c, d, e, f, g, h = args
        a, b = sorted([a, b])
        c, d = sorted([c, d])
        e, f = sorted([e, f])
        g, h = sorted([g, h])
        if tuple(sorted([a, b, e, f])) > tuple(sorted([c, d, g, h])):
            a, b, e, f, c, d, g, h = c, d, g, h, a, b, e, f
        if (a, b, c, d) > (e, f, g, h):
            a, b, c, d, e, f, g, h = e, f, g, h, a, b, c, d
        if name == "eqangle6":
            name = "eqangle"
        if name == "eqratio6":
            name = "eqratio"
        return (name,) + (a, b, c, d, e, f, g, h)

    if name in ["contri", "simtri", "simtri2", "contri2", "contri*", "simtri*"]:
        a, b, c, x, y, z = args
        (a, x), (b, y), (c, z) = sorted([(a, x), (b, y), (c, z)], key=sorted)
        (a, b, c), (x, y, z) = sorted([(a, b, c), (x, y, z)], key=sorted)
        return (name, a, b, c, x, y, z)

    return (name,) + tuple(args)


class EmptyDependency:
    """空依赖"""

    def __init__(self, level: int, rule_name: str):
        self.level = level
        self.rule_name = rule_name or ""
        self.why: List[Dependency] = []

    def populate(self, name: str, args: List[Any]) -> Dependency:
        dep = Dependency(name, args, self.rule_name, self.level)
        dep.why = list(self.why)
        return dep

    def copy(self) -> "EmptyDependency":
        other = EmptyDependency(self.level, self.rule_name)
        other.why = list(self.why)
        return other


class ProofState:
    """证明状态 - 存储已证明的命题"""

    def __init__(self):
        self.propositions: Set[Proposition] = set()
        self.dependencies: Dict[Tuple[str, ...], Optional[Dependency]] = {}

    def add(self, prop: Proposition, dep: Optional[Dependency] = None) -> bool:
        key = hashed(prop.predicate, list(prop.args))
        if key not in self.dependencies:
            self.propositions.add(prop)
            self.dependencies[key] = dep
            return True
        return False

    def contains(self, prop: Proposition) -> bool:
        key = hashed(prop.predicate, list(prop.args))
        return key in self.dependencies

    def get_dependency(self, prop: Proposition) -> Optional[Dependency]:
        key = hashed(prop.predicate, list(prop.args))
        return self.dependencies.get(key)

    def get_all_propositions(self) -> List[Proposition]:
        return list(self.propositions)

    def get_all(self) -> List[Proposition]:
        return list(self.propositions)

    def clear(self):
        self.propositions.clear()
        self.dependencies.clear()


class GeomGraph:
    """几何图结构 - 表示证明状态"""

    def __init__(self):
        self.type2nodes: Dict[type, List[GeomNode]] = {
            GeomPoint: [],
            GeomLine: [],
            GeomSegment: [],
            GeomCircle: [],
            GeomDirection: [],
            GeomLength: [],
            GeomAngle: [],
            GeomRatio: [],
            GeomMeasure: [],
            GeomValue: [],
        }
        self._name2point: Dict[str, GeomPoint] = {}
        self._name2node: Dict[str, GeomNode] = {}
        self.cache: Dict[Tuple, Dependency] = {}
        self._pair2line: Dict[Tuple[GeomPoint, GeomPoint], GeomLine] = {}
        self._triplet2circle: Dict[
            Tuple[GeomPoint, GeomPoint, GeomPoint], GeomCircle
        ] = {}

        self.aconst: Dict[Tuple[int, int], GeomAngle] = {}
        self.rconst: Dict[Tuple[int, int], GeomRatio] = {}

        self.halfpi, _ = self.get_or_create_const_ang(1, 2)

    def new_node(self, oftype: type, name: str = "") -> GeomNode:
        node = oftype(name, self)
        self.type2nodes[oftype].append(node)
        self._name2node[name] = node
        if isinstance(node, GeomPoint):
            self._name2point[name] = node
        return node

    def get_point(self, name: str) -> Optional[GeomPoint]:
        return self._name2point.get(name)

    def get_or_create_point(self, name: str, num: Optional[Point] = None) -> GeomPoint:
        if name in self._name2point:
            return self._name2point[name]
        p = cast(GeomPoint, self.new_node(GeomPoint, name))
        if num:
            p.num = num
        return p

    def all_points(self) -> List[GeomPoint]:
        return cast(List[GeomPoint], list(self.type2nodes[GeomPoint]))  #

    def _get_line(self, a: GeomPoint, b: GeomPoint) -> Optional[GeomLine]:
        linesa = a.neighbors(GeomLine)
        for line in b.neighbors(GeomLine):
            if line in linesa:
                return cast(GeomLine, line)  #
        return None

    def get_line_thru_pair(self, p1: GeomPoint, p2: GeomPoint) -> GeomLine:
        if (p1, p2) in self._pair2line:
            return self._pair2line[(p1, p2)]  #
        if (p2, p1) in self._pair2line:
            return self._pair2line[(p2, p1)]  #
        return self.get_new_line_thru_pair(p1, p2)

    def get_new_line_thru_pair(self, p1: GeomPoint, p2: GeomPoint) -> GeomLine:
        if p1.name.lower() > p2.name.lower():
            p1, p2 = p2, p1
        name = p1.name.lower() + p2.name.lower()
        line = cast(GeomLine, self.new_node(GeomLine, name))
        if p1.num and p2.num:
            line.num = Line(p1.num, p2.num)
        line.points = (p1, p2)  #
        self.connect(p1, line, None)  #
        self.connect(p2, line, None)  #
        self._pair2line[(p1, p2)] = line  #
        return line  #

    def get_circle_thru_triplet(
        self, p1: GeomPoint, p2: GeomPoint, p3: GeomPoint
    ) -> GeomCircle:
        p1, p2, p3 = sorted([p1, p2, p3], key=lambda x: x.name)
        if (p1, p2, p3) in self._triplet2circle:
            return self._triplet2circle[(p1, p2, p3)]  #
        return self.get_new_circle_thru_triplet(p1, p2, p3)

    def get_new_circle_thru_triplet(
        self, p1: GeomPoint, p2: GeomPoint, p3: GeomPoint
    ) -> GeomCircle:
        p1, p2, p3 = sorted([p1, p2, p3], key=lambda x: x.name)
        name = p1.name.lower() + p2.name.lower() + p3.name.lower()
        circle = cast(GeomCircle, self.new_node(GeomCircle, f"({name})"))
        if p1.num and p2.num and p3.num:
            circle.num = Circle(p1=p1.num, p2=p2.num, p3=p3.num)
        circle.points = (p1, p2, p3)  #
        self.connect(p1, circle, None)  #
        self.connect(p2, circle, None)  #
        self.connect(p3, circle, None)  #
        self._triplet2circle[(p1, p2, p3)] = circle  #
        return circle  #

    def connect(self, a: GeomNode, b: GeomNode, deps: Optional[Dependency]) -> None:
        a.connect_to(b, deps)
        b.connect_to(a, deps)

    def merge(self, nodes: List[GeomNode], deps: Dependency) -> Optional[GeomNode]:
        if len(nodes) < 2:
            return nodes[0] if nodes else None
        node0, *nodes1 = nodes
        all_nodes = self.type2nodes[type(node0)]
        for node in nodes:
            if node in all_nodes:
                node0 = node
                nodes1 = [n for n in nodes if n != node0]
                break
        return self.merge_into(node0, nodes1, deps)

    def merge_into(
        self, node0: GeomNode, nodes1: List[GeomNode], deps: Dependency
    ) -> GeomNode:
        node0.merge(nodes1, deps)  #
        for n in nodes1:
            if n.rep() != n:
                self.remove([n])
        return node0

    def remove(self, nodes: List[GeomNode]) -> None:
        if not nodes:
            return
        for node in nodes:
            all_nodes = self.type2nodes[type(nodes[0])]
            if node in all_nodes:
                all_nodes.remove(node)
            if node.name in self._name2node:
                self._name2node.pop(node.name)

    def is_equal(self, x: GeomNode, y: GeomNode, level: Optional[int] = None) -> bool:
        if x == y:
            return True
        if x._val is None or y._val is None:
            return False
        if x._val != y._val:  #
            return False
        return is_equiv(x._val, y._val, level)

    def is_perp(
        self, line1: GeomLine, line2: GeomLine, _level: Optional[int] = None
    ) -> bool:
        if line1 is None or line2 is None:
            return False
        if line1 == line2:
            return False

        perp_key = hashed("perp_lines", [line1.name, line2.name])
        if perp_key in self.cache:
            return True

        if line1.num and line2.num:
            return line1.num.is_perp(line2.num)

        return False

    def cache_dep(self, name: str, args: List[Any], dep: Dependency) -> None:
        h = hashed(name, [a.name if hasattr(a, "name") else str(a) for a in args])
        if h not in self.cache:
            self.cache[h] = dep

    def in_cache(self, name: str, args: List[Any]) -> bool:
        h = hashed(name, [a.name if hasattr(a, "name") else str(a) for a in args])
        return h in self.cache

    def get_or_create_const_ang(self, n: int, d: int) -> Tuple[GeomAngle, GeomAngle]:
        n, d = simplify(n, d)
        if (n, d) not in self.aconst:
            self._create_const_ang(n, d)
        ang1 = self.aconst[(n, d)]

        n, d = simplify(d - n, d)
        if (n, d) not in self.aconst:
            self._create_const_ang(n, d)
        ang2 = self.aconst[(n, d)]
        return ang1, ang2

    def _create_const_ang(self, n: int, d: int) -> None:
        n, d = simplify(n, d)
        ang = self.aconst[(n, d)] = cast(
            GeomAngle, self.new_node(GeomAngle, f"{n}pi/{d}")
        )  #
        ang.set_directions(None, None)  #

    def get_or_create_const_rat(self, n: int, d: int) -> Tuple[GeomRatio, GeomRatio]:
        n, d = simplify(n, d)
        if (n, d) not in self.rconst:
            self._create_const_rat(n, d)
        rat1 = self.rconst[(n, d)]

        if (d, n) not in self.rconst:
            self._create_const_rat(d, n)
        rat2 = self.rconst[(d, n)]
        return rat1, rat2

    def _create_const_rat(self, n: int, d: int) -> None:
        n, d = simplify(n, d)
        rat = self.rconst[(n, d)] = cast(
            GeomRatio, self.new_node(GeomRatio, f"{n}/{d}")
        )  #
        rat.set_lengths(None, None)  #


def simplify(n: int, d: int) -> Tuple[int, int]:
    def _gcd(x: int, y: int) -> int:
        while y:
            x, y = y, x % y
        return x

    g: int = _gcd(n, d)
    return (n // g, d // g)


def is_equiv(x: GeomNode, y: GeomNode, level: Optional[int] = None) -> bool:
    actual_level: Union[int, float] = level if level is not None else float("inf")
    return x.why_equal([y], actual_level) is not None  #


class RuleConstruction:
    """演绎规则中的构造项"""

    def __init__(self, name: str, args: List[str]):
        self.name = name
        self.args = args

    @classmethod
    def from_txt(cls, data: str) -> "RuleConstruction":
        parts = data.strip().split()
        if not parts:
            raise ValueError(f"空的构造: {data}")
        return cls(parts[0], parts[1:])

    def translate(self, mapping: Dict[str, GeomPoint]) -> List[Optional[GeomPoint]]:
        return [mapping.get(a) for a in self.args]

    def __repr__(self):
        return f"{self.name} {' '.join(self.args)}"


class Theorem:
    """演绎规则"""

    def __init__(
        self,
        premise: List[RuleConstruction],
        conclusion: List[RuleConstruction],
        name: str = "",
    ):
        if len(conclusion) != 1:
            raise ValueError("Cannot have more than one conclusion")
        self.name = name or "_".join([p.name for p in premise + conclusion])
        self.premise = premise
        self.conclusion = conclusion
        self.rule_name = ""

    @classmethod
    def from_txt(cls, data: str) -> "Theorem":
        if " => " not in data:
            raise ValueError(f"无效的规则格式: {data}")
        premises, conclusion = data.split(" => ")
        premises_list = [p.strip() for p in premises.split(",") if p.strip()]
        conclusion_list = [c.strip() for c in conclusion.split(",") if c.strip()]
        return cls(
            premise=[RuleConstruction.from_txt(p) for p in premises_list],
            conclusion=[RuleConstruction.from_txt(c) for c in conclusion_list],
        )


class Definition:
    """构造定义"""

    def __init__(
        self,
        construction: Construction,
        rely: Dict[str, str],
        deps: Any,
        basics: List[Tuple[List[str], List[Construction]]],
        numerics: List[Construction],
    ):
        self.construction = construction
        self.rely = rely
        self.deps = deps
        self.basics = basics
        self.numerics = numerics

    @classmethod
    def from_txt_file(
        cls, fname: str, to_dict: bool = False
    ) -> Dict[str, "Definition"]:
        with open(fname, "r", encoding="utf-8") as f:
            lines = f.read().split("\n")

        defs: Dict[str, "Definition"] = {}
        current_name: Optional[str] = None
        current_def: Dict[str, Any] = {}

        for line in lines:
            line = line.strip()
            if not line or line.startswith("#"):
                continue

            if not line.startswith(" ") and not line.startswith("\t"):
                if current_name:
                    defs[current_name] = cls._build_definition(
                        current_name, current_def
                    )
                parts = line.split()
                if len(parts) >= 1:
                    current_name = parts[0]
                    current_def = {
                        "construction": line,
                        "deps": [],
                        "basics": [],
                        "numerics": [],
                    }
            else:
                if current_name:
                    current_def["deps"].append(line.strip())

        if current_name:
            defs[current_name] = cls._build_definition(current_name, current_def)

        return defs if to_dict else defs

    @classmethod
    def _build_definition(cls, _name: str, data: Dict) -> "Definition":
        parts = data["construction"].split()
        construction = Construction(parts[0], tuple(parts[1:]), tuple(), [])
        return Definition(
            construction=construction,
            rely={},
            deps=data["deps"],
            basics=[],
            numerics=[],
        )


class SymbolicEngine:
    """符号引擎 - 实现几何命题的符号推理"""

    def __init__(self):
        self.graph = GeomGraph()
        self.proof_state = ProofState()
        self.definitions: Dict[str, Definition] = {}
        self.theorems: Dict[str, Theorem] = {}
        self.max_level = 100
        self.timeout = 600

        self._load_default_rules()

    def _load_default_rules(self):
        self._load_default_theorems()

    def _load_default_theorems(self):
        for rule in GeometryRules.RULES:
            try:
                premises_str = ", ".join(rule.premises)
                rule_str = f"{premises_str} => {rule.conclusion}"
                th = Theorem.from_txt(rule_str)
                th.rule_name = rule.name
                self.theorems[th.rule_name] = th
            except Exception:
                pass

    def load_definitions(self, filepath: str):
        self.definitions = Definition.from_txt_file(filepath, to_dict=True)

    def load_theorems(self, filepath: str):
        with open(filepath, "r", encoding="utf-8") as f:
            for i, line in enumerate(f):
                line = line.strip()
                if not line or line.startswith("#"):
                    continue
                try:
                    th = Theorem.from_txt(line)
                    th.rule_name = f"r{i:02d}"
                    self.theorems[th.rule_name] = th
                except Exception:
                    pass

    def reset(self):
        self.graph = GeomGraph()
        self.proof_state = ProofState()

    def add_point(
        self, name: str, coords: Optional[Tuple[float, float]] = None
    ) -> GeomPoint:
        num = Point(coords[0], coords[1]) if coords else None
        return self.graph.get_or_create_point(name, num)

    def add_coll(
        self, points: List[str], deps: Optional[EmptyDependency] = None
    ) -> List[Dependency]:
        if len(points) < 3:
            return []
        pts = [self.graph.get_or_create_point(p) for p in points]
        added = []

        for p1, p2 in [(pts[0], pts[1]), (pts[0], pts[2])]:
            _ = self.graph.get_line_thru_pair(p1, p2)

        all_lines = []
        for p1, p2 in [
            (pts[i], pts[j]) for i in range(len(pts)) for j in range(i + 1, len(pts))
        ]:
            all_lines.append(self.graph.get_line_thru_pair(p1, p2))

        if deps is None:
            deps = EmptyDependency(level=0, rule_name="given")
        dep = deps.populate("coll", pts)
        self.graph.cache_dep("coll", pts, dep)
        added.append(dep)

        return added

    def add_para(
        self, points: List[str], deps: Optional[EmptyDependency] = None
    ) -> List[Dependency]:
        if len(points) != 4:
            return []
        a, b, c, d = [self.graph.get_or_create_point(p) for p in points]
        _ = self.graph.get_line_thru_pair(a, b)
        _ = self.graph.get_line_thru_pair(c, d)

        added = []
        if deps is None:
            deps = EmptyDependency(level=0, rule_name="given")
        dep = deps.populate("para", [a, b, c, d])
        self.graph.cache_dep("para", [a, b, c, d], dep)
        added.append(dep)

        return added

    def add_perp(
        self, points: List[str], deps: Optional[EmptyDependency] = None
    ) -> List[Dependency]:
        if len(points) != 4:
            return []
        a, b, c, d = [self.graph.get_or_create_point(p) for p in points]
        _ = self.graph.get_line_thru_pair(a, b)
        _ = self.graph.get_line_thru_pair(c, d)

        added = []
        if deps is None:
            deps = EmptyDependency(level=0, rule_name="given")
        dep = deps.populate("perp", [a, b, c, d])
        self.graph.cache_dep("perp", [a, b, c, d], dep)
        added.append(dep)

        return added

    def add_cong(
        self, points: List[str], deps: Optional[EmptyDependency] = None
    ) -> List[Dependency]:
        if len(points) != 4:
            return []
        a, b, c, d = [self.graph.get_or_create_point(p) for p in points]

        added = []
        if deps is None:
            deps = EmptyDependency(level=0, rule_name="given")
        dep = deps.populate("cong", [a, b, c, d])
        self.graph.cache_dep("cong", [a, b, c, d], dep)
        added.append(dep)

        return added

    def add_midp(
        self, points: List[str], deps: Optional[EmptyDependency] = None
    ) -> List[Dependency]:
        if len(points) != 3:
            return []
        m, a, b = [self.graph.get_or_create_point(p) for p in points]

        added = []
        if deps is None:
            deps = EmptyDependency(level=0, rule_name="given")
        added.extend(self.add_coll([m.name, a.name, b.name], deps))
        added.extend(self.add_cong([m.name, a.name, m.name, b.name], deps))

        dep = deps.populate("midp", [m, a, b])
        self.graph.cache_dep("midp", [m, a, b], dep)
        added.append(dep)

        return added

    def add_cyclic(
        self, points: List[str], deps: Optional[EmptyDependency] = None
    ) -> List[Dependency]:
        if len(points) < 4:
            return []
        pts = [self.graph.get_or_create_point(p) for p in points]

        _ = self.graph.get_circle_thru_triplet(pts[0], pts[1], pts[2])

        added = []
        if deps is None:
            deps = EmptyDependency(level=0, rule_name="given")
        dep = deps.populate("cyclic", pts[:4])
        self.graph.cache_dep("cyclic", pts[:4], dep)
        added.append(dep)

        return added

    def add_circle(
        self, points: List[str], deps: Optional[EmptyDependency] = None
    ) -> List[Dependency]:
        if len(points) != 4:
            return []
        o, a, b, c = [self.graph.get_or_create_point(p) for p in points]

        added = []
        if deps is None:
            deps = EmptyDependency(level=0, rule_name="given")
        added.extend(self.add_cong([o.name, a.name, o.name, b.name], deps))
        added.extend(self.add_cong([o.name, a.name, o.name, c.name], deps))

        dep = deps.populate("circle", [o, a, b, c])
        self.graph.cache_dep("circle", [o, a, b, c], dep)
        added.append(dep)

        return added

    def add_eqangle(
        self, points: List[str], deps: Optional[EmptyDependency] = None
    ) -> List[Dependency]:
        if len(points) != 8:
            return []
        pts = [self.graph.get_or_create_point(p) for p in points]

        added = []
        if deps is None:
            deps = EmptyDependency(level=0, rule_name="given")
        dep = deps.populate("eqangle", pts)
        self.graph.cache_dep("eqangle", pts, dep)
        added.append(dep)

        return added

    def add_eqratio(
        self, points: List[str], deps: Optional[EmptyDependency] = None
    ) -> List[Dependency]:
        if len(points) != 8:
            return []
        pts = [self.graph.get_or_create_point(p) for p in points]

        added = []
        if deps is None:
            deps = EmptyDependency(level=0, rule_name="given")
        dep = deps.populate("eqratio", pts)
        self.graph.cache_dep("eqratio", pts, dep)
        added.append(dep)

        return added

    def check(self, name: str, args: List[Any]) -> bool:
        if name == "ncoll":
            return self.check_ncoll(args)
        if name == "npara":
            return self.check_npara(args)
        if name == "nperp":
            return self.check_nperp(args)
        if name == "midp":
            return self.check_midp(args)
        if name == "cong":
            return self.check_cong(args)
        if name == "perp":
            return self.check_perp(args)
        if name == "para":
            return self.check_para(args)
        if name == "coll":
            return self.check_coll(args)
        if name == "cyclic":
            return self.check_cyclic(args)
        if name == "circle":
            return self.check_circle(args)
        if name in ["eqangle", "eqangle6"]:
            return self.check_eqangle(args)
        if name in ["eqratio", "eqratio6"]:
            return self.check_eqratio(args)
        if name in ["simtri", "simtri2", "simtri*"]:
            return self.check_simtri(args)
        if name in ["contri", "contri2", "contri*"]:
            return self.check_contri(args)
        if name == "diff":
            a, b = args
            return not a.num.close(b.num) if (a.num and b.num) else True
        return False

    def check_coll(self, points: List[GeomPoint]) -> bool:
        if len(points) < 3:
            return True
        line2count: Dict[GeomNode, int] = defaultdict(lambda: 0)
        for p in points:
            for line in p.neighbors(GeomLine):
                line2count[line] += 1
        return any(count == len(points) for count in line2count.values())

    def check_ncoll(self, points: List[GeomPoint]) -> bool:
        if self.check_coll(points):
            return False
        if all(p.num for p in points):
            return not self._numerical_check_coll([p.num for p in points])
        return True

    def _numerical_check_coll(self, points: List[Point]) -> bool:
        if len(points) < 3:
            return True
        a, b = points[:2]
        line = Line(a, b)
        for p in points[2:]:
            if abs(line(p.x, p.y)) > ATOM:
                return False
        return True

    def check_para(self, points: List[GeomPoint]) -> bool:
        if len(points) != 4:
            return False
        a, b, c, d = points
        if a == b or c == d:
            return False

        key = hashed("para", [p.name for p in points])
        if key in self.graph.cache:
            return True

        key_rev = hashed("para", [p.name for p in [c, d, a, b]])
        if key_rev in self.graph.cache:
            return True

        ab = self.graph._get_line(a, b)
        cd = self.graph._get_line(c, d)
        if not ab or not cd:
            return False
        return self.graph.is_equal(ab, cd)

    def check_npara(self, points: List[GeomPoint]) -> bool:
        if self.check_para(points):
            return False
        if all(p.num for p in points):
            return not self._numerical_check_para([p.num for p in points])
        return True

    def _numerical_check_para(self, points: List[Point]) -> bool:
        a, b, c, d = points
        ab = Line(a, b)
        cd = Line(c, d)
        return ab.is_parallel(cd)

    def check_perp(self, points: List[GeomPoint]) -> bool:
        if len(points) != 4:
            return False
        a, b, c, d = points

        key = hashed("perp", [p.name for p in points])
        if key in self.graph.cache:
            return True

        key_rev = hashed("perp", [p.name for p in [c, d, a, b]])
        if key_rev in self.graph.cache:
            return True

        key_swap1 = hashed("perp", [p.name for p in [b, a, c, d]])
        if key_swap1 in self.graph.cache:
            return True

        key_swap2 = hashed("perp", [p.name for p in [a, b, d, c]])
        if key_swap2 in self.graph.cache:
            return True

        key_swap3 = hashed("perp", [p.name for p in [c, d, b, a]])
        if key_swap3 in self.graph.cache:
            return True

        ab = self.graph._get_line(a, b)
        cd = self.graph._get_line(c, d)
        if ab and cd:
            if self.graph.is_perp(ab, cd):
                return True

        if all(p.num for p in [a, b, c, d]):
            return self._numerical_check_perp([p.num for p in [a, b, c, d]])
        return False

    def _numerical_check_perp(self, points: List[Point]) -> bool:
        a, b, c, d = points
        ab = Line(a, b)
        cd = Line(c, d)
        return ab.is_perp(cd)

    def check_nperp(self, points: List[GeomPoint]) -> bool:
        if self.check_perp(points):
            return False
        if all(p.num for p in points):
            return not self._numerical_check_perp([p.num for p in points])
        return True

    def check_cong(self, points: List[GeomPoint]) -> bool:
        if len(points) != 4:
            return False
        a, b, c, d = points
        if {a, b} == {c, d}:
            return True
        if all(p.num for p in [a, b, c, d]):
            return close_enough(a.num.distance(b.num), c.num.distance(d.num))
        return False

    def check_midp(self, points: List[GeomPoint]) -> bool:
        if len(points) != 3:
            return False
        if not self.check_coll(points):
            return False
        m, a, b = points
        return self.check_cong([m, a, m, b])

    def check_cyclic(self, points: List[GeomPoint]) -> bool:
        if len(points) < 4:
            return True
        circle2count: Dict[GeomNode, int] = defaultdict(lambda: 0)
        for p in points:
            for c in p.neighbors(GeomCircle):
                circle2count[c] += 1
        return any(count == len(points) for count in circle2count.values())

    def check_circle(self, points: List[GeomPoint]) -> bool:
        if len(points) != 4:
            return False
        o, a, b, c = points
        return self.check_cong([o, a, o, b]) and self.check_cong([o, a, o, c])

    def check_eqangle(self, points: List[GeomPoint]) -> bool:
        if len(points) != 8:
            return False
        a, b, c, d, e, f, g, h = points

        if {a, b} == {c, d} and {e, f} == {g, h}:
            return True
        if {a, b} == {e, f} and {c, d} == {g, h}:
            return True

        if all(p.num for p in points):
            return self._numerical_check_eqangle([p.num for p in points])
        return False

    def _numerical_check_eqangle(self, points: List[Point]) -> bool:
        a, b, c, d, e, f, g, h = points

        ab = Line(a, b)
        cd = Line(c, d)
        ef = Line(e, f)
        gh = Line(g, h)

        if ab.is_parallel(cd):
            return ef.is_parallel(gh)
        if ef.is_parallel(gh):
            return ab.is_parallel(cd)

        def bring_together(a, b, c, d):
            ab = Line(a, b)
            cd = Line(c, d)
            try:
                x = line_line_intersection(ab, cd)
                unit = Circle(center=x, radius=1.0)
                y, _ = line_circle_intersection(ab, unit)
                z, _ = line_circle_intersection(cd, unit)
                return x, y, x, z
            except (ValueError, TypeError):
                return a, b, c, d

        a, b, c, d = bring_together(a, b, c, d)
        e, f, g, h = bring_together(e, f, g, h)

        ba = b - a
        dc = d - c
        fe = f - e
        hg = h - g

        sameclock = (ba.x * dc.y - ba.y * dc.x) * (fe.x * hg.y - fe.y * hg.x) > 0
        if not sameclock:
            ba = ba * -1.0

        a1 = math.atan2(fe.y, fe.x)
        a2 = math.atan2(hg.y, hg.x)
        x = a1 - a2

        a3 = math.atan2(ba.y, ba.x)
        a4 = math.atan2(dc.y, dc.x)
        y = a3 - a4

        xy = (x - y) % (2 * math.pi)
        return close_enough(xy, 0, tol=1e-11) or close_enough(
            xy, 2 * math.pi, tol=1e-11
        )

    def check_eqratio(self, points: List[GeomPoint]) -> bool:
        if len(points) != 8:
            return False
        a, b, c, d, e, f, g, h = points

        if {a, b} == {c, d} and {e, f} == {g, h}:
            return True
        if {a, b} == {e, f} and {c, d} == {g, h}:
            return True

        if all(p.num for p in points):
            return self._numerical_check_eqratio([p.num for p in points])
        return False

    def _numerical_check_eqratio(self, points: List[Point]) -> bool:
        a, b, c, d, e, f, g, h = points
        ab = a.distance(b)
        cd = c.distance(d)
        ef = e.distance(f)
        gh = g.distance(h)
        return close_enough(ab * gh, cd * ef)

    def check_simtri(self, points: List[GeomPoint]) -> bool:
        if len(points) != 6:
            return False
        _a, _b, _c, _x, _y, _z = points
        if all(p.num for p in points):
            return self._numerical_check_simtri([p.num for p in points])
        return False

    def _numerical_check_simtri(self, points: List[Point]) -> bool:
        a, b, c, x, y, z = points
        ab = a.distance(b)
        bc = b.distance(c)
        ca = c.distance(a)
        xy = x.distance(y)
        yz = y.distance(z)
        zx = z.distance(x)
        tol = 1e-9
        return close_enough(ab * yz, bc * xy, tol) and close_enough(
            bc * zx, ca * yz, tol
        )

    def check_contri(self, points: List[GeomPoint]) -> bool:
        if len(points) != 6:
            return False
        _a, _b, _c, _x, _y, _z = points
        if all(p.num for p in points):
            return self._numerical_check_contri([p.num for p in points])
        return False

    def _numerical_check_contri(self, points: List[Point]) -> bool:
        a, b, c, x, y, z = points
        ab = a.distance(b)
        bc = b.distance(c)
        ca = c.distance(a)
        xy = x.distance(y)
        yz = y.distance(z)
        zx = z.distance(x)
        tol = 1e-9
        return (
            close_enough(ab, xy, tol)
            and close_enough(bc, yz, tol)
            and close_enough(ca, zx, tol)
        )

    def verify_proposition(self, prop: Proposition) -> bool:
        predicate = prop.predicate
        args = list(prop.args)

        points = []
        for arg in args:
            p = self.graph.get_point(arg)
            if p is None:
                p = self.graph.get_or_create_point(arg)
            points.append(p)

        return self.check(predicate, points)

    def verify_problem(self, problem: Problem) -> Tuple[bool, str]:
        for const in problem.constructions:
            try:
                self._apply_construction(const)
            except Exception as e:
                return False, f"构造失败: {e}"

        if problem.goal:
            is_valid = self.verify_proposition(problem.goal)
            return is_valid, "验证成功" if is_valid else "目标命题不成立"

        return True, "无目标命题"

    def _apply_construction(self, const: Construction) -> List[Dependency]:
        name = const.name
        args = list(const.output_points) + list(const.input_points)

        if name == "triangle":
            return self._construct_triangle(args)
        if name == "midpoint":
            return self._construct_midpoint(args)
        if name == "foot":
            return self._construct_foot(args)
        if name == "intersection_ll":
            return self._construct_intersection_ll(args)
        if name == "on_line":
            return self._construct_on_line(args)
        if name == "on_tline":
            return self._construct_on_tline(args)
        if name == "on_circle":
            return self._construct_on_circle(args)
        if name == "on_circum":
            return self._construct_on_circum(args)
        if name == "circle":
            return self._construct_circle(args)
        if name == "circumcenter":
            return self._construct_circumcenter(args)
        if name == "orthocenter":
            return self._construct_orthocenter(args)
        if name == "incenter":
            return self._construct_incenter(args)
        if name == "centroid":
            return self._construct_centroid(args)
        return []

    def _construct_triangle(self, args: List[str]) -> List[Dependency]:
        if len(args) < 3:
            return []
        _ = self.add_point(args[0], (0.0, 0.0))
        _ = self.add_point(args[1], (1.0, 0.0))
        _ = self.add_point(args[2], (0.5, math.sqrt(3) / 2))
        return []

    def _construct_midpoint(self, args: List[str]) -> List[Dependency]:
        if len(args) != 2:
            return []
        m_name, a_name, b_name = args[0], args[1], args[2] if len(args) > 2 else args[1]
        a = self.graph.get_or_create_point(a_name)
        b = self.graph.get_or_create_point(b_name)
        if a.num and b.num:
            m_num = (a.num + b.num) * 0.5
            _ = self.add_point(m_name, (m_num.x, m_num.y))
        else:
            _ = self.add_point(m_name)
        return self.add_midp([m_name, a_name, b_name])

    def _construct_foot(self, args: List[str]) -> List[Dependency]:
        if len(args) != 3:
            return []
        _ = args[0]
        _ = args[1]
        _ = args[2] if len(args) > 3 else args[2]
        return []

    def _construct_intersection_ll(self, args: List[str]) -> List[Dependency]:
        if len(args) != 4:
            return []
        return []

    def _construct_on_line(self, args: List[str]) -> List[Dependency]:
        if len(args) != 2:
            return []
        return []

    def _construct_on_tline(self, args: List[str]) -> List[Dependency]:
        if len(args) != 3:
            return []
        return []

    def _construct_on_circle(self, args: List[str]) -> List[Dependency]:
        if len(args) != 2:
            return []
        return []

    def _construct_on_circum(self, args: List[str]) -> List[Dependency]:
        if len(args) != 3:
            return []
        return []

    def _construct_circle(self, args: List[str]) -> List[Dependency]:
        if len(args) != 3:
            return []
        return []

    def _construct_circumcenter(self, args: List[str]) -> List[Dependency]:
        if len(args) != 3:
            return []
        return []

    def _construct_orthocenter(self, args: List[str]) -> List[Dependency]:
        if len(args) != 3:
            return []
        return []

    def _construct_incenter(self, args: List[str]) -> List[Dependency]:
        if len(args) != 3:
            return []
        return []

    def _construct_centroid(self, args: List[str]) -> List[Dependency]:
        if len(args) != 3:
            return []
        return []

    def solve(
        self,
        problem: Problem,
        max_level: Optional[int] = None,
        timeout: Optional[int] = None,
    ) -> Tuple[bool, List[Dependency], str]:
        max_level = max_level if max_level is not None else self.max_level
        timeout = timeout if timeout is not None else self.timeout

        self.reset()

        for const in problem.constructions:
            try:
                self._apply_construction(const)
            except Exception as e:
                return False, [], f"构造失败: {e}"

        if not problem.goal:
            return True, [], "无目标命题"

        all_deps = []
        for level in range(max_level):
            added = self._bfs_one_level(level)
            all_deps.extend(added)

            if self.verify_proposition(problem.goal):
                return True, all_deps, "证明成功"

            if not added:
                break

        return False, all_deps, "未能证明"

    def deduce(self, state: ProofState, max_steps: int = 10) -> List[Proposition]:
        """从给定状态进行演绎推理

        Args:
            state: 初始证明状态
            max_steps: 最大推理步数

        Returns:
            新推导出的命题列表
        """
        new_props = []

        for prop in state.get_all():
            deps = self._add_proposition_to_graph(prop)
            if deps:
                for dep in deps:
                    if hasattr(dep, "args") and dep.name:
                        points = dep.args
                        if all(isinstance(p, GeomPoint) for p in points):
                            point_names = tuple(p.name for p in points)
                            new_prop = Proposition(predicate=dep.name, args=point_names)
                            if not state.contains(new_prop):
                                state.add(new_prop, dep)
                                new_props.append(new_prop)

        for step in range(max_steps):
            added = self._bfs_one_level(step)
            if not added:
                break

            for dep in added:
                if hasattr(dep, "args") and dep.name:
                    points = dep.args
                    if all(isinstance(p, GeomPoint) for p in points):
                        point_names = tuple(p.name for p in points)
                        prop = Proposition(predicate=dep.name, args=point_names)
                        if not state.contains(prop):
                            state.add(prop, dep)
                            new_props.append(prop)

        return new_props

    def can_prove(
        self,
        target: Proposition,
        premises: Optional[List[Proposition]] = None,
        max_steps: int = 10,
    ) -> Tuple[bool, List[Proposition]]:
        """尝试从前提证明目标命题

        Args:
            target: 目标命题
            premises: 前提命题列表
            max_steps: 最大推理步数

        Returns:
            (是否可证明, 推导出的命题列表)
        """
        derived = []

        if premises:
            for prop in premises:
                deps = self._add_proposition_to_graph(prop)
                if deps:
                    for dep in deps:
                        if hasattr(dep, "args") and dep.name:
                            points = dep.args
                            if all(isinstance(p, GeomPoint) for p in points):
                                point_names = tuple(p.name for p in points)
                                new_prop = Proposition(
                                    predicate=dep.name, args=point_names
                                )
                                derived.append(new_prop)

        for step in range(max_steps):
            added = self._bfs_one_level(step)
            if not added:
                break

            for dep in added:
                if hasattr(dep, "args") and dep.name:
                    points = dep.args
                    if all(isinstance(p, GeomPoint) for p in points):
                        point_names = tuple(p.name for p in points)
                        prop = Proposition(predicate=dep.name, args=point_names)
                        derived.append(prop)

            if self.verify_proposition(target):
                return True, derived

        return False, derived

    def get_rules(self) -> List[Theorem]:
        """获取所有已加载的定理规则"""
        return list(self.theorems.values())

    def _add_proposition_to_graph(self, prop: Proposition) -> List[Dependency]:
        """将命题添加到图中

        Returns:
            添加的依赖项列表
        """
        predicate = prop.predicate
        args = list(prop.args)

        points = []
        for arg in args:
            p = self.graph.get_or_create_point(arg)
            points.append(p)

        if predicate == "coll" and len(points) >= 3:
            return self.add_coll(args)
        if predicate == "para" and len(points) == 4:
            return self.add_para(args)
        if predicate == "perp" and len(points) == 4:
            return self.add_perp(args)
        if predicate == "cong" and len(points) == 4:
            return self.add_cong(args)
        if predicate == "midp" and len(points) == 3:
            return self.add_midp(args)
        if predicate == "cyclic" and len(points) >= 4:
            return self.add_cyclic(args)
        if predicate == "eqangle" and len(points) == 8:
            return self.add_eqangle(args)
        if predicate == "eqratio" and len(points) == 8:
            return self.add_eqratio(args)

        return []

    def _bfs_one_level(self, level: int) -> List[Dependency]:
        added = []

        for _, theorem in self.theorems.items():
            try:
                matches = self._match_theorem(theorem)
                for match in matches:
                    dep = self._apply_theorem(theorem, match, level)
                    if dep:
                        added.extend(dep)
            except Exception:
                pass

        return added

    def _match_theorem(self, theorem: Theorem) -> List[Dict[str, GeomPoint]]:
        matches = []

        if not theorem.premise:
            return [{}]

        first_premise = theorem.premise[0]
        name = first_premise.name
        args = first_premise.args

        if name in ["coll", "para", "perp", "cong", "midp", "cyclic"]:
            cached_relations = self._get_cached_relations(name)
            for rel_args in cached_relations:
                if len(rel_args) == len(args):
                    initial_mapping = dict(zip(args, rel_args))
                    result_mappings = self._match_remaining_premises(
                        theorem, initial_mapping, 1
                    )
                    matches.extend(result_mappings)

        return matches[:100]

    def _match_remaining_premises(
        self, theorem: Theorem, mapping: Dict[str, GeomPoint], premise_idx: int
    ) -> List[Dict[str, GeomPoint]]:
        if premise_idx >= len(theorem.premise):
            return [mapping]

        premise = theorem.premise[premise_idx]
        name = premise.name
        args = premise.args

        known_vars = [a for a in args if a in mapping]
        unknown_vars = [a for a in args if a not in mapping]

        if not unknown_vars:
            points = [mapping.get(a) for a in args]
            if None not in points:
                key = hashed(name, [p.name for p in points if p is not None])
                if key in self.graph.cache:
                    return self._match_remaining_premises(
                        theorem, mapping, premise_idx + 1
                    )
            return []

        cached_relations = self._get_cached_relations(name)
        results = []

        for rel_args in cached_relations:
            if len(rel_args) != len(args):
                continue

            compatible = True
            for var in known_vars:
                var_idx = args.index(var)
                if mapping[var] != rel_args[var_idx]:
                    compatible = False
                    break

            if compatible:
                new_mapping = dict(mapping)
                for i, var in enumerate(args):
                    if var not in new_mapping:
                        new_mapping[var] = rel_args[i]

                sub_results = self._match_remaining_premises(
                    theorem, new_mapping, premise_idx + 1
                )
                results.extend(sub_results)

        return results

    def _get_cached_relations(self, name: str) -> List[Tuple[GeomPoint, ...]]:
        """从缓存中获取指定类型的所有关系"""
        relations = []
        for key, _dep in self.graph.cache.items():
            if isinstance(key, tuple) and len(key) > 0 and key[0] == name:
                point_names = key[1:]
                points = []
                valid = True
                for pname in point_names:
                    p = self.graph.get_point(pname)
                    if p is None:
                        valid = False
                        break
                    points.append(p)
                if valid:
                    relations.append(tuple(points))
        return relations

    def _check_remaining_premises(
        self, theorem: Theorem, mapping: Dict[str, GeomPoint]
    ) -> bool:
        for premise in theorem.premise[1:]:
            name = premise.name
            args = premise.args
            try:
                points = [mapping.get(a) for a in args]
                if None in points:
                    return False
                if not self.check(name, points):
                    return False
            except Exception:
                return False
        return True

    def _apply_theorem(
        self, theorem: Theorem, mapping: Dict[str, GeomPoint], level: int
    ) -> List[Dependency]:
        conclusion = theorem.conclusion[0]
        name = conclusion.name
        args = conclusion.args

        try:
            points = [mapping.get(a) for a in args]
            if None in points:
                return []

            if self.graph.in_cache(name, points):
                return []

            deps = EmptyDependency(level, theorem.rule_name)
            for premise in theorem.premise:
                p_args = [mapping.get(a) for a in premise.args]
                if None not in p_args:
                    key = hashed(
                        premise.name, [p.name for p in p_args if p is not None]
                    )
                    if key in self.graph.cache:
                        deps.why.append(self.graph.cache[key])

            if name == "coll":
                return self.add_coll([p.name for p in points if p is not None], deps)
            if name == "para":
                return self.add_para([p.name for p in points if p is not None], deps)
            if name == "perp":
                return self.add_perp([p.name for p in points if p is not None], deps)
            if name == "cong":
                return self.add_cong([p.name for p in points if p is not None], deps)
            if name == "midp":
                return self.add_midp([p.name for p in points if p is not None], deps)
            if name == "cyclic":
                return self.add_cyclic([p.name for p in points if p is not None], deps)
            if name == "eqangle":
                return self.add_eqangle([p.name for p in points if p is not None], deps)
            if name == "eqratio":
                return self.add_eqratio([p.name for p in points if p is not None], deps)
            dep = deps.populate(name, points)
            self.graph.cache_dep(name, points, dep)
            return [dep]

        except Exception:
            return []


def run_symbolic_engine_test():
    engine = SymbolicEngine()

    _ = engine.add_point("A", (0.0, 0.0))
    _ = engine.add_point("B", (1.0, 0.0))
    _ = engine.add_point("C", (0.5, math.sqrt(3) / 2))

    print("测试基本命题验证:")

    prop1 = Proposition.from_string("coll A B C")
    print(f"  coll A B C: {engine.verify_proposition(prop1)}")

    prop2 = Proposition.from_string("ncoll A B C")
    print(f"  ncoll A B C: {engine.verify_proposition(prop2)}")

    _ = engine.add_point("D", (2.0, 0.0))
    prop3 = Proposition.from_string("coll A B D")
    print(f"  coll A B D: {engine.verify_proposition(prop3)}")

    prop4 = Proposition.from_string("para A B C D")
    print(f"  para A B C D: {engine.verify_proposition(prop4)}")

    _ = engine.add_point("E", (0.0, 1.0))
    prop5 = Proposition.from_string("perp A B A E")
    print(f"  perp A B A E: {engine.verify_proposition(prop5)}")

    _ = engine.add_point("F", (1.0, 1.0))
    prop6 = Proposition.from_string("cong A B E F")
    print(f"  cong A B E F: {engine.verify_proposition(prop6)}")

    print("\n测试问题求解:")
    problem_str = "a b c = triangle ? coll a b c"
    problem = GeometryParser.parse_problem(problem_str)
    _, _, msg = engine.solve(problem)
    print(f"  问题: {problem_str}")
    print(f"  结果: {msg}")

    print("\n符号引擎测试完成!")


if __name__ == "__main__":
    run_symbolic_engine_test()
